remote.destination:
${syslog\-collector\-name}

  ${ipaddress}
  ${port}
  <#if certificate?has_content || client\-auth\-est\-profile\-name?has_content>


        <#if certificate?has_content>

            ${certificate}

        <#elseif client\-auth\-est\-profile\-name?has_content>

            ${client\-auth\-est\-profile\-name}

        </#if>


  </#if>
  <#if pinned\-ca\-list?has_content || server\-auth\-est\-profile\-name?has_content>

      <#if pinned\-ca\-list?has_content>
        ${pinned\-ca\-list}
      <#elseif server\-auth\-est\-profile\-name?has_content>
        ${server\-auth\-est\-profile\-name}
      </#if>

  </#if>
  <#if idle\-time?has_content && max\-probes?has_content && probe\-interval?has_content>

        ${idle\-time}
        ${max\-probes}
        ${probe\-interval}

  </#if>
  <#if tls\-version?has_content || cipher\-suite?has_content>

      <#if tls\-version?has_content>

          tlscmn:${tls\-version}

      </#if>
      <#if cipher\-suite?has_content>

          tlscsa:${cipher\-suite}

      </#if>

  </#if>

<#if facility?has_content && severity?has_content>


        ${facility}
        ${severity}

          <#if advance\-action?has_content>
              ${advance\-action}
          </#if>
          <#if advance\-compare?has_content>
              ${advance\-compare}
          </#if>



</#if>
<#if pattern\-match?has_content>
  ${pattern\-match}
</#if>
